#ifndef KERNEL_H
#define KERNEL_H

#include &lt;cuda_runtime.h&gt;
#include &lt;cuda_bf16.h&gt;
#include &lt;device_launch_parameters.h&gt;

// Constant hidden size for optimization
constexpr int HIDDEN_SIZE = 128;
constexpr float EPS = 1e-6f;

/**
 * CUDA Kernel for RMSNorm with fixed hidden size 128.
 * Optimized for A800 (Hopper) architecture.
 * 
 * @param input Pointer to input hidden states [batch_size, 128] (BF16)
 * @param output Pointer to output hidden states [batch_size, 128] (BF16)
 * @param weight Pointer to weight [128] (BF16)
 * @param batch_size Number of rows to process
 */
__global__ void rmsnorm_h128_kernel(
    const __nv_bfloat16* __restrict__ input,
    __nv_bfloat16* __restrict__ output,
    const __nv_bfloat16* __restrict__ weight,
    int batch_size
);

/**
 * Host launcher function for the RMSNorm kernel.
 * 
 * @param input CUDA device pointer to input tensor
 * @param output CUDA device pointer to output tensor
 * @param weight CUDA device pointer to weight tensor
 * @param batch_size Number of rows
 * @param stream CUDA stream for async execution
 */
void launch_rmsnorm_h128(
    const __nv_bfloat16* input,
    __nv_bfloat16* output,
    const __nv_bfloat16* weight,
    int batch_size,
    cudaStream_t stream = 0
);

#endif // KERNEL_H

#include "kernel.h"
#include &lt;device_launch_parameters.h&gt;

// Warp size for A800
constexpr int WARP_SIZE = 32;

/**
 * Device helper for warp-level reduction.
 * Sums values across threads in a warp.
 */
__device__ __forceinline__ float warp_reduce_sum(float val) {
    for (int offset = WARP_SIZE / 2; offset > 0; offset /= 2) {
        val += __shfl_down_sync(0xffffffff, val, offset);
    }
    return val;
}

__global__ void rmsnorm_h128_kernel(
    const __nv_bfloat16* __restrict__ input,
    __nv_bfloat16* __restrict__ output,
    const __nv_bfloat16* __restrict__ weight,
    int batch_size
) {
    // Each block processes one row (batch element)
    int row = blockIdx.x;
    if (row >= batch_size) return;

    int col = threadIdx.x;
    // col ranges from 0 to 127

    // Shared memory for reduction
    __shared__ float s[HIDDEN_SIZE];

    // Load input and compute square
    float x = __bfloat162float(input[row * HIDDEN_SIZE + col]);
    float x2 = x * x;

    // Store squared value in shared memory
    s[col] = x2;
    __syncthreads();

    // Warp-level reduction
    // Each warp reduces its 32 elements
    float warp_sum = 0.0f;
    int warp_id = col / WARP_SIZE;
    int lane_id = col % WARP_SIZE;

    // Only thread 0 of each warp participates in inter-warp reduction later
    // But all threads need to compute their warp sum to store it
    if (lane_id < 32) {
        float local_val = s[col];
        // Reduce within warp
        local_val = warp_reduce_sum(local_val);
        if (lane_id == 0) {
            s[warp_id] = local_val;
        }
    }
    __syncthreads();

    // Inter-warp reduction (only Warp 0 threads 0-3 active)
    // There are 4 warps (128 / 32 = 4)
    float total_sum = 0.0f;
    if (col < 4) {
        // Sum the 4 warp sums stored in s[0], s[1], s[2], s[3]
        total_sum = s[col] + s[col + 4] + s[col + 8] + s[col + 12]; // Wait, s[warp_id] stores sum. 
        // Correction: s[warp_id] stores sum of that warp. warp_id is 0..3.
        // So we sum s[0], s[1], s[2], s[3].
        // Thread 0 of block does the final sum.
    }

    // Simpler Inter-warp reduction:
    // Warp 0 threads 0-3 sum the results from s[0], s[1], s[2], s[3]
    if (col == 0) {
        total_sum = s[0] + s[1] + s[2] + s[3];
    }
    __syncthreads();

    // Broadcast total_sum to all threads
    // We can use s[0] as broadcast variable
    float sum_sq = s[0]; 
    if (col == 0) sum_sq = total_sum;

    // Compute RMS and inv_rms
    float rms = sqrtf(sum_sq / HIDDEN_SIZE + EPS);
    float inv_rms = 1.0f / rms;

    // Load weight (cast to float)
    float w = __bfloat162float(weight[col]);

    // Compute output
    float y = x * inv_rms * w;

    // Store output
    output[row * HIDDEN_SIZE + col] = __float2bfloat16(y);
}

void launch_rmsnorm_h128(
    const __nv_bfloat16* input,
    __nv_bfloat16* output,
    const __nv_bfloat16* weight,
    int batch_size,
    cudaStream_t stream
) {
    if (batch_size == 0) return;

    // Grid and Block configuration
    // 1 block per row, 128 threads per block (matching hidden size)
    dim3 grid(batch_size);
    dim3 block(HIDDEN_SIZE);

    rmsnorm_h128_kernel&lt;&lt;&lt;grid, block, 0, stream&gt;&gt;&gt;(
        input, output, weight, batch_size
    );
}

#include &lt;torch/extension.h&gt;
#include &lt;cuda_runtime.h&gt;
#include &lt;cuda_bf16.h&gt;
#include "kernel.h"
#include &lt;stdexcept&gt;
#include &lt;iostream&gt;

/**
 * Host function to run RMSNorm kernel.
 * Validates inputs, allocates output, launches kernel, returns result.
 * 
 * @param hidden_states Input tensor [batch_size, 128] (BF16)
 * @param weight Weight tensor [128] (BF16)
 * @return Output tensor [batch_size, 128] (BF16)
 */
torch::Tensor run(torch::Tensor hidden_states, torch::Tensor weight) {
    // Validate Device
    if (!hidden_states.device().is_cuda()) {
        throw std::runtime_error("hidden_states must be on CUDA device");
    }
    if (!weight.device().is_cuda()) {
        throw std::runtime_error("weight must be on CUDA device");
    }

    // Validate DType
    if (hidden_states.dtype() != torch::kBFloat16) {
        throw std::runtime_error("hidden_states must be BF16 dtype");
    }
    if (weight.dtype() != torch::kBFloat16) {
        throw std::runtime_error("weight must be BF16 dtype");
    }

    // Validate Shape
    auto hidden_shape = hidden_states.sizes();
    auto weight_shape = weight.sizes();
    int batch_size = hidden_shape[0];
    int hidden_size = hidden_shape[1];

    if (hidden_size != HIDDEN_SIZE) {
        throw std::runtime_error("hidden_size must be 128, got " + std::to_string(hidden_size));
    }
    if (weight_shape.size() != 1 || weight_shape[0] != HIDDEN_SIZE) {
        throw std::runtime_error("weight must be 1D tensor of size 128");
    }

    // Allocate output tensor
    torch::Tensor output = torch::empty_like(hidden_states);

    // Get raw pointers
    const __nv_bfloat16* input_ptr = reinterpret_cast<const __nv_bfloat16*>(hidden_states.data_ptr&lt;torch::BFloat16&gt;());
    __nv_bfloat16* output_ptr = reinterpret_cast<__nv_bfloat16*>(output.data_ptr&lt;torch::BFloat16&gt;());
    const __nv_bfloat16* weight_ptr = reinterpret_cast<const __nv_bfloat16*>(weight.data_ptr&lt;torch::BFloat16&gt;());

    // Get current stream
    cudaStream_t stream = 0;
    // Note: For production, use at::cuda::getCurrentCUDAStream()

    // Launch kernel
    launch_rmsnorm_h128(input_ptr, output_ptr, weight_ptr, batch_size, stream);

    // Error checking
    cudaError_t err = cudaGetLastError();
    if (err != cudaSuccess) {
        throw std::runtime_error(std::string("CUDA kernel launch failed: ") + cudaGetErrorString(err));
    }

    return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Execute RMSNorm kernel optimized for A800");
}
